/*
 * Bus Structure Simulation
 * Demonstrates: Data bus, Address bus, Control bus operations
 * Simulates CPU-Memory communication via bus structure
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

// Bus configuration constants
#define DATA_BUS_WIDTH 32 // 32-bit data bus
#define ADDRESS_BUS_WIDTH 16 // 16-bit address bus (64KB memory)
#define MEMORY_SIZE 65536 // 64KB memory

// Control bus signal definitions
typedef enum {
 BUS_IDLE = 0,
 BUS_READ = 1,
 BUS_WRITE = 2
} BusOperation;

// Bus structure
typedef struct {
 // Data bus (bidirectional)
 unsigned int data; // 32-bit data bus

 // Address bus (CPU -> Memory)
 unsigned short address; // 16-bit address bus

 // Control bus signals
 BusOperation operation; // Read/Write control
 unsigned char mreq; // Memory request signal
 unsigned char rd; // Read enable
 unsigned char wr; // Write enable
 unsigned char ready; // Memory ready signal
} Bus;

// Memory module
typedef struct {
 unsigned char memory[MEMORY_SIZE];
 unsigned char busy;
} Memory;

// Initialize bus
void init_bus(Bus *bus) {
 bus->data = 0;
 bus->address = 0;
 bus->operation = BUS_IDLE;
 bus->mreq = 0;
 bus->rd = 0;
 bus->wr = 0;
 bus->ready = 0;
}

// Initialize memory
void init_memory(Memory *mem) {
 memset(mem->memory, 0, MEMORY_SIZE);
 mem->busy = 0;

 // Load some sample data
 mem->memory[0] = 0xDE;
 mem->memory[1] = 0xAD;
 mem->memory[2] = 0xBE;
 mem->memory[3] = 0xEF;
}

// Simulate memory read operation (data transfer from memory to CPU)
unsigned char memory_read(Memory *mem, unsigned short address) {
 if (address >= MEMORY_SIZE) {
 printf("Error: Address out of range!\n");
 return 0;
 }
 return mem->memory[address];
}

// Simulate memory write operation (data transfer from CPU to memory)
void memory_write(Memory *mem, unsigned short address, unsigned char data) {
 if (address >= MEMORY_SIZE) {
 printf("Error: Address out of range!\n");
 return;
 }
 mem->memory[address] = data;
}

// Execute bus cycle - demonstrates bus phases
void execute_bus_cycle(Bus *bus, Memory *mem, BusOperation op, unsigned short addr, unsigned int *data) {
 printf("\n--- Bus Cycle ---\n");

 // Phase 1: Address Phase - CPU places address on address bus
 bus->address = addr;
 bus->mreq = 1; // Memory request
 printf("Address Phase: Address=0x%04X placed on %d-bit address bus\n", 
 addr, ADDRESS_BUS_WIDTH);

 // Phase 2: Data Phase - Perform read or write
 if (op == BUS_READ) {
 bus->rd = 1;
 bus->wr = 0;
 bus->operation = BUS_READ;

 // Simulate memory access time
 *data = memory_read(mem, addr);
 bus->data = *data;

 printf("Data Phase: READ operation\n");
 printf(" Data bus (0x%02X) -> CPU from memory address 0x%04X\n", 
 bus->data, addr);
 } else if (op == BUS_WRITE) {
 bus->rd = 0;
 bus->busy = 1;
 bus->operation = BUS_WRITE;
 bus->data = *data;

 // Write to memory
 memory_write(mem, addr, (unsigned char)(*data & 0xFF));

 printf("Data Phase: WRITE operation\n");
 printf(" CPU -> Data bus (0x%02X) -> Memory address 0x%04X\n", 
 bus->data, addr);
 }

 // Phase 3: Acknowledgment
 bus->ready = 1;
 printf("Acknowledgment: Transfer complete, bus released\n");

 // Reset bus
 bus->mreq = 0;
 bus->rd = 0;
 bus->wr = 0;
 bus->ready = 0;
 bus->operation = BUS_IDLE;
}

// Display bus configuration
void display_bus_config() {
 printf("=======================================\n");
 printf(" BUS STRUCTURE SIMULATION\n");
 printf("=======================================\n");
 printf("Bus Configuration:\n");
 printf(" - Data Bus: %d-bit (bidirectional)\n", DATA_BUS_WIDTH);
 printf(" - Address Bus: %d-bit (unidirectional)\n", ADDRESS_BUS_WIDTH);
 printf(" - Control Bus: Read/Write, MREQ, Ready signals\n");
 printf(" - Memory Size: %d bytes (%d KB)\n", MEMORY_SIZE, MEMORY_SIZE/1024);
 printf("\n");
}

int main() {
 Bus system_bus;
 Memory system_memory;
 unsigned int data;
 unsigned short address;

 // Initialize components
 init_bus(&system_bus);
 init_memory(&system_memory);
 display_bus_config();

 // Example 1: Read from memory
 printf("=== READ OPERATION (CPU reads from Memory) ===\n");
 address = 0x0000; // Read from first memory location
 data = 0;
 execute_bus_cycle(&system_bus, &system_memory, BUS_READ, address, &data);

 // Example 2: Write to memory
 printf("\n=== WRITE OPERATION (CPU writes to Memory) ===\n");
 address = 0x0010; // Write to address 16
 data = 0x42; // Write value 66 (ASCII 'B')
 execute_bus_cycle(&system_bus, &system_memory, BUS_WRITE, address, &data);

 // Example 3: Read back the written data
 printf("\n=== READ BACK WRITTEN DATA ===\n");
 address = 0x0010;
 data = 0;
 execute_bus_cycle(&system_bus, &system_memory, BUS_READ, address, &data);

 // Demonstrate address bus limitation
 printf("\n=== ADDRESS BUS LIMITATION DEMO ===\n");
 printf("With %d-bit address bus, can address %d locations (0x0000 to 0x%04X)\n",
 ADDRESS_BUS_WIDTH, MEMORY_SIZE, MEMORY_SIZE - 1);
 printf("Attempting to access address beyond limit...\n");
 address = 0xFFFF + 1; // Try to access beyond memory
 data = 0;
 execute_bus_cycle(&system_bus, &system_memory, BUS_READ, address, &data);

 return 0;
}
